321	                    onValueChange={(value) => {
322	                      if (!value) return;
323	                      updateSettings({ codexServiceTier: value });
324	                    }}
325	                  >
326	                    <SelectTrigger>
327	                      <SelectValue />
328	                    </SelectTrigger>
329	                    <SelectPopup alignItemWithTrigger={false}>
330	                      {APP_SERVICE_TIER_OPTIONS.map((option) => (
331	                        <SelectItem key={option.value} value={option.value}>
332	                          <div className="flex min-w-0 items-center gap-2">
333	                            {option.value === "fast" ? (
334	                              <ZapIcon className="size-3.5 text-amber-500" />
335	                            ) : (
336	                              <span className="size-3.5 shrink-0" aria-hidden="true" />
337	                            )}
338	                            <span className="truncate">{option.label}</span>
339	                          </div>
340	                        </SelectItem>
341	                      ))}
342	                    </SelectPopup>
