 * Each theme specifies CSS color values for key UI surface areas.
 * The web app applies these as CSS custom properties on the document root.
 */

// ---------------------------------------------------------------------------
// Color slot types
// ---------------------------------------------------------------------------

/** Color values for a single theme area (e.g. sidebar, editor). */
export interface ThemeAreaColors {
  readonly background: string;
  readonly foreground: string;
}

/** Full color palette for a T3 Code theme. */
export interface ThemeColors {
  /** Page-level background and foreground. */
  readonly background: string;
  readonly foreground: string;

  /** Primary accent color used for buttons, links, and focus rings. */
  readonly accent: string;
  readonly accentForeground: string;

  /** Sidebar navigation panel. */
  readonly sidebar: ThemeAreaColors;

  /** Main editor / chat content area. */
  readonly editor: ThemeAreaColors;

