import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILTIN_THEMES,
  getBuiltinTheme,
  themeColorsToCssProperties,
  type Theme,
  type ThemeId,
} from "@t3tools/shared/theme";

type ColorScheme = "light" | "dark" | "system";
type ThemeSnapshot = {
  colorScheme: ColorScheme;
  customThemeId: ThemeId | null;
  systemDark: boolean;
};

const COLOR_SCHEME_KEY = "t3code:theme";
const CUSTOM_THEME_KEY = "t3code:custom-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorScheme(): ColorScheme {
  const raw = localStorage.getItem(COLOR_SCHEME_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredCustomThemeId(): ThemeId | null {
  const raw = localStorage.getItem(CUSTOM_THEME_KEY);
  if (raw && getBuiltinTheme(raw)) return raw;
  return null;
}

// ---------------------------------------------------------------------------
// CSS custom property management
// ---------------------------------------------------------------------------

/** Tracked property names so we can remove them when the custom theme is cleared. */
let appliedCssProperties: string[] = [];

function applyCssThemeProperties(theme: Theme) {
  const root = document.documentElement;
  const entries = themeColorsToCssProperties(theme.colors);
  const names: string[] = [];
  for (const [prop, value] of entries) {
    root.style.setProperty(prop, value);
    names.push(prop);
  }
  appliedCssProperties = names;
}

function clearCssThemeProperties() {
  const root = document.documentElement;
  for (const prop of appliedCssProperties) {
    root.style.removeProperty(prop);
  }
  appliedCssProperties = [];
}

// ---------------------------------------------------------------------------
// DOM class / custom property application
// ---------------------------------------------------------------------------

function applyTheme(colorScheme: ColorScheme, customThemeId: ThemeId | null, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const customTheme = customThemeId ? getBuiltinTheme(customThemeId) : null;

  // Resolve dark/light from custom theme when present, otherwise from color scheme
  const isDark = customTheme
    ? customTheme.isDark
    : colorScheme === "dark" || (colorScheme === "system" && getSystemDark());

  document.documentElement.classList.toggle("dark", isDark);

  // Apply or clear CSS custom properties
  if (customTheme) {
    applyCssThemeProperties(customTheme);
  } else {
    clearCssThemeProperties();
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredColorScheme(), getStoredCustomThemeId());

function getSnapshot(): ThemeSnapshot {
  const colorScheme = getStoredColorScheme();
  const customThemeId = getStoredCustomThemeId();
  const systemDark = colorScheme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.colorScheme === colorScheme &&
    lastSnapshot.customThemeId === customThemeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { colorScheme, customThemeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    const stored = getStoredColorScheme();
    const customId = getStoredCustomThemeId();
    if (stored === "system" && !customId) applyTheme("system", null, true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_SCHEME_KEY || e.key === CUSTOM_THEME_KEY) {
      applyTheme(getStoredColorScheme(), getStoredCustomThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { colorScheme, customThemeId } = snapshot;

  const customTheme = customThemeId ? getBuiltinTheme(customThemeId) ?? null : null;

  const resolvedTheme: "light" | "dark" = customTheme
    ? customTheme.isDark ? "dark" : "light"
    : colorScheme === "system"
      ? snapshot.systemDark ? "dark" : "light"
      : colorScheme;

  /** Set color scheme (light / dark / system). Clears any custom theme. */
  const setTheme = useCallback((next: ColorScheme) => {
    localStorage.setItem(COLOR_SCHEME_KEY, next);
    localStorage.removeItem(CUSTOM_THEME_KEY);
    applyTheme(next, null, true);
    emitChange();
  }, []);

  /** Activate a built-in custom theme by ID. */
  const setCustomTheme = useCallback((id: ThemeId | null) => {
    if (id === null) {
      localStorage.removeItem(CUSTOM_THEME_KEY);
      applyTheme(getStoredColorScheme(), null, true);
    } else {
      localStorage.setItem(CUSTOM_THEME_KEY, id);
      applyTheme(getStoredColorScheme(), id, true);
    }
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(colorScheme, customThemeId);
  }, [colorScheme, customThemeId]);

  return {
    /** Current color-scheme preference ("light" | "dark" | "system"). */
    theme: colorScheme,
    setTheme,
    resolvedTheme,
    /** Active custom theme object, or null when using default color scheme. */
    customTheme,
    /** Active custom theme ID, or null. */
    customThemeId,
    setCustomTheme,
    /** All available built-in themes. */
    builtinThemes: BUILTIN_THEMES,
  } as const;
}

export type { ColorScheme, Theme, ThemeId };

