import type { Theme, ThemeId } from "@t3tools/shared/theme";

import { useTheme } from "~/hooks/useTheme";
import { cn } from "~/lib/utils";

// ---------------------------------------------------------------------------
// Swatch — miniature theme preview
// ---------------------------------------------------------------------------

function ThemeSwatch({ theme, className }: { theme: Theme; className?: string }) {
  const { colors } = theme;

  return (
    <div
      className={cn(
        "relative flex h-16 w-24 shrink-0 overflow-hidden rounded-md border border-border",
        className,
      )}
      aria-hidden="true"
    >
      {/* Sidebar sliver */}
      <div
        className="flex w-5 flex-col gap-0.5 px-0.5 pt-1"
        style={{ background: colors.sidebar.background }}
      >
        {/* Tiny fake nav items */}
        <div
          className="h-1 w-full rounded-sm opacity-60"
          style={{ background: colors.sidebar.foreground }}
        />
        <div
          className="h-1 w-3/4 rounded-sm opacity-40"
          style={{ background: colors.sidebar.foreground }}
        />
        <div
          className="h-1 w-full rounded-sm opacity-30"
          style={{ background: colors.sidebar.foreground }}
        />
      </div>

      {/* Main area */}
      <div className="flex flex-1 flex-col" style={{ background: colors.editor.background }}>
        {/* Fake editor lines */}
        <div className="flex flex-1 flex-col gap-0.5 px-1 pt-1">
          <div
            className="h-1 w-full rounded-sm opacity-40"
            style={{ background: colors.editor.foreground }}
          />
          <div
            className="h-1 w-4/5 rounded-sm opacity-25"
            style={{ background: colors.editor.foreground }}
          />
          <div
            className="h-1 w-3/5 rounded-sm opacity-35"
            style={{ background: colors.editor.foreground }}
          />
          {/* Accent highlight bar */}
          <div className="mt-auto mb-0.5 h-1 w-2/5 rounded-sm" style={{ background: colors.accent }} />
        </div>

        {/* Terminal strip */}
        <div
          className="flex h-3 items-center px-1"
          style={{ background: colors.terminal.background }}
        >
          <div
            className="h-0.5 w-3/4 rounded-sm opacity-40"
            style={{ background: colors.terminal.foreground }}
          />
        </div>

        {/* Status bar */}
        <div
          className="flex h-2 items-center px-1"
          style={{ background: colors.statusBar.background }}
        >
          <div
            className="h-0.5 w-1/2 rounded-sm opacity-50"
            style={{ background: colors.statusBar.foreground }}
          />
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { customThemeId, setCustomTheme, builtinThemes, setTheme } = useTheme();

  const handleSelect = (id: ThemeId) => {
    if (customThemeId === id) {
      // Deselect → revert to OS color scheme
      setCustomTheme(null);
      setTheme("system");
    } else {
      setCustomTheme(id);
    }
  };

  return (
    <div className="space-y-3">
      <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
        {builtinThemes.map((theme) => {
          const selected = customThemeId === theme.id;
          return (
            <button
              key={theme.id}
              type="button"
              role="radio"
              aria-checked={selected}
              aria-label={theme.name}
              className={cn(
                "group flex flex-col items-center gap-2 rounded-xl border px-3 py-3 text-left transition-colors",
                selected
                  ? "border-primary/60 bg-primary/8"
                  : "border-border bg-background hover:bg-accent",
              )}
              onClick={() => handleSelect(theme.id)}
            >
              <ThemeSwatch theme={theme} />

              <div className="flex w-full items-center justify-between gap-2">
                <div className="flex flex-col">
                  <span className="text-sm font-medium text-foreground">{theme.name}</span>
                  <span className="text-[11px] text-muted-foreground">
                    {theme.isDark ? "Dark" : "Light"}
                  </span>
                </div>
                {selected ? (
                  <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                    Active
                  </span>
                ) : null}
              </div>
            </button>
          );
        })}
      </div>

      {customThemeId ? (
        <p className="text-xs text-muted-foreground">
          Click the active theme again to deselect and return to system colors.
        </p>
      ) : null}
    </div>
  );
}

